// purchaseService.js
import axios from 'axios';

const API_BASE_URL = 'http://localhost:8080/api';

const purchaseService = {
    // ==================== PURCHASE ORDERS ====================
    
    // Get all orders
    getAllOrders: async (page = 0, size = 10) => {
        try {
            const response = await axios.get(`${API_BASE_URL}/purchase-orders`, {
                params: { page, size }
            });
            return response.data;
        } catch (error) {
            console.error('Error fetching purchase orders:', error);
            throw error;
        }
    },

    // Get order by ID
    getOrderById: async (id) => {
        try {
            const response = await axios.get(`${API_BASE_URL}/purchase-orders/${id}`);
            return response.data;
        } catch (error) {
            console.error('Error fetching purchase order with ID', id, ':', error);
            throw error;
        }
    },

    // Get order by PO number
    getOrderByNumber: async (poNumber) => {
        try {
            const response = await axios.get(`${API_BASE_URL}/purchase-orders/number/${poNumber}`);
            return response.data;
        } catch (error) {
            console.error('Error fetching purchase order by number', poNumber, ':', error);
            throw error;
        }
    },

    // Get orders by supplier
    getOrdersBySupplier: async (supplierId, page = 0, size = 10) => {
        try {
            const response = await axios.get(`${API_BASE_URL}/purchase-orders/supplier/${supplierId}`, {
                params: { page, size }
            });
            return response.data;
        } catch (error) {
            console.error('Error fetching orders by supplier:', error);
            throw error;
        }
    },

    // Create order
    createOrder: async (orderData) => {
        try {
            const response = await axios.post(`${API_BASE_URL}/purchase-orders`, orderData);
            return response.data;
        } catch (error) {
            console.error('Error creating purchase order:', error);
            throw error;
        }
    },

    // Update order
    updateOrder: async (id, orderData) => {
        try {
            const response = await axios.put(`${API_BASE_URL}/purchase-orders/${id}`, orderData);
            return response.data;
        } catch (error) {
            console.error('Error updating purchase order:', error);
            throw error;
        }
    },

    // Convert to invoice
    convertToInvoice: async (id) => {
        try {
            const response = await axios.post(`${API_BASE_URL}/purchase-orders/${id}/convert`);
            return response.data;
        } catch (error) {
            console.error('Error converting PO to invoice:', error);
            throw error;
        }
    },

    // Delete order
    deleteOrder: async (id) => {
        try {
            await axios.delete(`${API_BASE_URL}/purchase-orders/${id}`);
        } catch (error) {
            console.error('Error deleting purchase order:', error);
            throw error;
        }
    },

    // ==================== PURCHASE INVOICES ====================
    
    // Get all invoices
    getAllInvoices: async (page = 0, size = 10) => {
        try {
            const response = await axios.get(`${API_BASE_URL}/purchase-invoices`, {
                params: { page, size }
            });
            return response.data;
        } catch (error) {
            console.error('Error fetching purchase invoices:', error);
            throw error;
        }
    },

    // Get invoice by ID
    getInvoiceById: async (id) => {
        try {
            const response = await axios.get(`${API_BASE_URL}/purchase-invoices/${id}`);
            return response.data;
        } catch (error) {
            console.error('Error fetching invoice with ID', id, ':', error);
            throw error;
        }
    },

    // Get invoice by invoice number
    getInvoiceByNumber: async (invoiceNo) => {
        try {
            const response = await axios.get(`${API_BASE_URL}/purchase-invoices/number/${invoiceNo}`);
            return response.data;
        } catch (error) {
            console.error('Error fetching invoice by number', invoiceNo, ':', error);
            throw error;
        }
    },

    // Create invoice
    createInvoice: async (invoiceData) => {
        try {
            const response = await axios.post(`${API_BASE_URL}/purchase-invoices`, invoiceData);
            return response.data;
        } catch (error) {
            console.error('Error creating purchase invoice:', error);
            throw error;
        }
    },

    // Update invoice
    updateInvoice: async (id, invoiceData) => {
        try {
            const response = await axios.put(`${API_BASE_URL}/purchase-invoices/${id}`, invoiceData);
            return response.data;
        } catch (error) {
            console.error('Error updating purchase invoice:', error);
            throw error;
        }
    },

    // Make payment
    makePayment: async (id, amount) => {
        try {
            const response = await axios.post(`${API_BASE_URL}/purchase-invoices/${id}/payment`, null, {
                params: { amount }
            });
            return response.data;
        } catch (error) {
            console.error('Error making payment:', error);
            throw error;
        }
    },

    // Delete invoice
    deleteInvoice: async (id) => {
        try {
            await axios.delete(`${API_BASE_URL}/purchase-invoices/${id}`);
        } catch (error) {
            console.error('Error deleting purchase invoice:', error);
            throw error;
        }
    }
};

export default purchaseService;
